// Pointwise (1x1) conv2d, stride=1, tiled-streaming contract.
//   IC=64, OC=256, IH=IW=56, OH=OW=56, MP=4.
//   channel_tile=32 -> IN_BEATS=2, OUT_BEATS=8 per pixel.
//   Latency: IN_BEATS + OC_PASSES * (MP*K_TOTAL + 6) = 2 + 64*262 = 16770.
module node_conv_202 (
    input  wire              clk,
    input  wire              rst_n,
    input  wire              valid_in,
    output reg               ready_in,
    input  wire [255:0]      data_in,
    output reg               valid_out,
    output reg  [255:0]      data_out
);
    localparam IC = 64, OC = 256;
    localparam OH = 56, OW = 56;
    localparam KH = 1, KW = 1;
    localparam K_TOTAL = IC*KH*KW;
    localparam MP = 4;
    localparam OC_PASSES = (OC + MP - 1) / MP;
    localparam CHANNEL_TILE = 32;
    localparam IN_BEATS  = (IC + CHANNEL_TILE - 1) / CHANNEL_TILE;
    localparam OUT_BEATS = (OC + CHANNEL_TILE - 1) / CHANNEL_TILE;
    localparam TILE_BITS = CHANNEL_TILE * 8;
    localparam integer SCALE_MULT  = 15821;
    localparam integer SCALE_SHIFT = 21;
    localparam integer PROD_W        = 16;
    localparam integer ACC_W         = 24;
    localparam integer BIAS_W        = 32;
    localparam integer BIASED_W      = 34;
    localparam integer SCALE_CONST_W = 16;
    localparam integer SCALED_W      = 50;
    localparam signed [SCALE_CONST_W-1:0] SCALE_MULT_CONST = SCALE_MULT;
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF =
        {{(SCALED_W-1){1'b0}}, 1'b1} << (SCALE_SHIFT - 1);
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF_M1 =
        SCALE_ROUND_HALF - {{(SCALED_W-1){1'b0}}, 1'b1};
    (* rom_style="block", ram_style="block" *) reg signed [7:0]  weights [0:OC*K_TOTAL-1];
    (* rom_style="block", ram_style="block" *) reg signed [31:0] biases  [0:OC-1];
    initial begin
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_202_weights.hex", weights);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_202_bias.hex", biases);
    end
    localparam [2:0] ST_LOAD=3'd0, ST_RUNNING=3'd1, ST_BIAS=3'd2, ST_SCALE=3'd3, ST_OUTPUT=3'd4, ST_EMIT=3'd5;
    reg [2:0] state;
    reg [IC*8-1:0]  in_latch;
    reg [OC*8-1:0]  out_pack;
    reg [1:0] in_beat_idx;
    reg [3:0] out_beat_idx;
    reg [5:0] pixel_row;
    reg [5:0] pixel_col;
    reg [6:0] oc_group;
    reg [2:0] lane_counter;
    reg [6:0] k_counter;
    reg signed [7:0] weight_q;
    reg signed [7:0] act_q;
    (* use_dsp = "yes" *) reg signed [PROD_W-1:0] mul_q;
    reg [2:0] mac_lane_q1;
    reg [2:0] mac_lane_q2;
    reg       mac_valid_q1;
    reg       mac_valid_q2;
    reg       mac_done_issuing;
    reg signed [ACC_W-1:0]    acc    [0:MP-1];
    reg signed [BIASED_W-1:0] biased [0:MP-1];
    reg signed [SCALED_W-1:0] scaled [0:MP-1];
    reg signed [SCALED_W-1:0] v_tmp;
    integer i; integer lane; integer global_oc;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state<=ST_LOAD; ready_in<=1'b1; valid_out<=1'b0; data_out<=0;
            in_beat_idx<=0; out_beat_idx<=0; pixel_row<=0; pixel_col<=0;
            oc_group<=0; lane_counter<=0; k_counter<=0;
            in_latch<=0; out_pack<=0;
            weight_q<=0; act_q<=0; mul_q<=0;
            mac_lane_q1<=0; mac_lane_q2<=0;
            mac_valid_q1<=0; mac_valid_q2<=0; mac_done_issuing<=0;
            v_tmp<=0;
            for (i=0;i<MP;i=i+1) begin acc[i]<=0; biased[i]<=0; scaled[i]<=0; end
        end else begin
            case (state)
                ST_LOAD: begin
                    valid_out <= 1'b0;
                    if (valid_in && ready_in) begin
                        in_latch[in_beat_idx*TILE_BITS +: TILE_BITS] <= data_in;
                        if (in_beat_idx == IN_BEATS - 1) begin
                            in_beat_idx<=0; ready_in<=1'b0; state<=ST_RUNNING;
                            oc_group<=0; lane_counter<=0; k_counter<=0;
                            mac_done_issuing<=0; mac_valid_q1<=0; mac_valid_q2<=0;
                            for (i=0;i<MP;i=i+1) acc[i]<=0;
                        end else in_beat_idx <= in_beat_idx + 1'b1;
                    end
                end
                ST_RUNNING: begin
                    if (!mac_done_issuing) begin
                        weight_q     <= weights[((oc_group*MP)+lane_counter)*K_TOTAL + k_counter];
                        act_q        <= in_latch[k_counter*8 +: 8];
                        mac_lane_q1  <= lane_counter;
                        mac_valid_q1 <= 1'b1;
                        if (k_counter == K_TOTAL-1) begin
                            k_counter <= 0;
                            if (lane_counter == MP-1) begin
                                lane_counter<=0; mac_done_issuing<=1'b1;
                            end else lane_counter <= lane_counter + 1'b1;
                        end else k_counter <= k_counter + 1'b1;
                    end else mac_valid_q1 <= 1'b0;
                    mul_q <= $signed(weight_q) * $signed(act_q);
                    mac_lane_q2 <= mac_lane_q1;
                    mac_valid_q2 <= mac_valid_q1;
                    if (mac_valid_q2) acc[mac_lane_q2] <= acc[mac_lane_q2] + mul_q;
                    if (mac_done_issuing && !mac_valid_q1 && !mac_valid_q2) begin
                        state <= ST_BIAS; mac_done_issuing <= 1'b0;
                    end
                end
                ST_BIAS: begin
                    for (lane=0; lane<MP; lane=lane+1)
                        biased[lane] <= acc[lane] + $signed(biases[oc_group*MP + lane]);
                    state <= ST_SCALE;
                end
                ST_SCALE: begin
                    for (lane=0; lane<MP; lane=lane+1)
                        scaled[lane] <= $signed(biased[lane]) * $signed(SCALE_MULT_CONST);
                    state <= ST_OUTPUT;
                end
                ST_OUTPUT: begin
                    for (lane=0; lane<MP; lane=lane+1) begin
                        global_oc = oc_group*MP + lane;
                        v_tmp = (scaled[lane] + (scaled[lane][SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
                        out_pack[global_oc*8 +: 8] <= (v_tmp > 127) ? 8'sd127 : (v_tmp < -128) ? -8'sd128 : v_tmp[7:0];
                    end
                    if (oc_group == OC_PASSES-1) begin
                        valid_out <= 1'b1; data_out <= out_pack[0 +: TILE_BITS];
                        out_beat_idx <= 4'd1; state <= ST_EMIT; oc_group <= 0;
                    end else begin
                        oc_group <= oc_group + 1'b1; lane_counter<=0; k_counter<=0;
                        mac_done_issuing<=0; mac_valid_q1<=0; mac_valid_q2<=0;
                        for (i=0;i<MP;i=i+1) acc[i]<=0;
                        state <= ST_RUNNING;
                    end
                end
                ST_EMIT: begin
                    if (out_beat_idx < OUT_BEATS) begin
                        data_out <= out_pack[out_beat_idx*TILE_BITS +: TILE_BITS];
                        valid_out <= 1'b1;
                        out_beat_idx <= out_beat_idx + 1'b1;
                    end else begin
                        valid_out <= 1'b0; out_beat_idx <= 0; ready_in <= 1'b1;
                        if (pixel_col == OW-1) begin
                            pixel_col <= 0;
                            if (pixel_row == OH-1) pixel_row <= 0;
                            else pixel_row <= pixel_row + 1'b1;
                        end else pixel_col <= pixel_col + 1'b1;
                        state <= ST_LOAD;
                    end
                end
                default: state <= ST_LOAD;
            endcase
        end
    end
endmodule
